mapper.delete:
DELETE FROM novel_chapter_version
WHERE chapter_id = #{chapterId}
  AND published = 0
  AND id NOT IN (
    SELECT id FROM (
        SELECT id
        FROM novel_chapter_version
        WHERE chapter_id = #{chapterId}
          AND deleted = 0
        ORDER BY create_time DESC
        LIMIT #{keepCount}
    ) AS tmp
  )
